class MempoolMonitorBot {
  constructor(options = {}) {
    this.Web3 = require("web3");
    this.web3 = options.web3 || new this.Web3(options.wsUrl);
    this.account = this.web3.eth.accounts.wallet.add(options.privateKey);
    this.address = this.account.address;
    this.enabled = true;
    this.minProfitWei = BigInt(options.minProfitWei || "0");
    this.gasBump = BigInt(options.gasBump || "2000000000");
    this.maxGasPriceWei = BigInt(options.maxGasPriceWei || "300000000000");
    this.targets = new Set((options.targets || []).map((a) => a.toLowerCase()));
    this.pairChecks = options.pairChecks || [];
    this.pendingSub = null;
    this.seen = new Set();
    this.onOpportunity = typeof options.onOpportunity === "function" ? options.onOpportunity : async () => {};
  }

  async start() {
    if (!this.web3.currentProvider || !this.web3.currentProvider.on) {
      throw new Error("WebSocket provider required for pending transaction monitoring");
    }

    this.pendingSub = this.web3.eth.subscribe("pendingTransactions");
    this.pendingSub.on("data", async (txHash) => {
      if (!this.enabled) return;
      if (this.seen.has(txHash)) return;
      this.seen.add(txHash);
      try {
        const tx = await this.web3.eth.getTransaction(txHash);
        if (!tx || !tx.to) return;
        if (this.targets.size && !this.targets.has(tx.to.toLowerCase())) return;
        await this.evaluateTransaction(tx);
      } catch (_) {}
      if (this.seen.size > 50000) this.seen.clear();
    });

    this.pendingSub.on("error", () => {});
    return true;
  }

  stop() {
    this.enabled = false;
    if (this.pendingSub && this.pendingSub.unsubscribe) {
      try {
        this.pendingSub.unsubscribe();
      } catch (_) {}
    }
  }

  async evaluateTransaction(tx) {
    const opportunities = await this.findArbitrage(tx);
    for (const opp of opportunities) {
      if (opp && BigInt(opp.expectedProfitWei || "0") >= this.minProfitWei) {
        await this.onOpportunity(opp, tx);
        await this.submitFrontRun(opp, tx);
      }
    }
  }

  async findArbitrage(tx) {
    const results = [];
    for (const check of this.pairChecks) {
      try {
        const opp = await check(tx, this.web3);
        if (opp) results.push(opp);
      } catch (_) {}
    }
    return results;
  }

  async submitFrontRun(opp, targetTx) {
    const nonce = await this.web3.eth.getTransactionCount(this.address, "pending");
    const baseGasPrice = targetTx.gasPrice ? BigInt(targetTx.gasPrice.toString()) : BigInt(await this.web3.eth.getGasPrice());
    const gasPrice = baseGasPrice + this.gasBump;

    if (gasPrice > this.maxGasPriceWei) return null;

    const tx = {
      from: this.address,
      to: opp.to,
      data: opp.data || "0x",
      value: opp.value ? this.web3.utils.toHex(opp.value.toString()) : "0x0",
      gas: opp.gasLimit ? this.web3.utils.toHex(opp.gasLimit) : this.web3.utils.toHex(300000),
      gasPrice: this.web3.utils.toHex(gasPrice.toString()),
      nonce: this.web3.utils.toHex(nonce),
      chainId: opp.chainId || await this.web3.eth.getChainId()
    };

    const signed = await this.web3.eth.accounts.signTransaction(tx, this.account.privateKey);
    if (!signed.rawTransaction) return null;
    return await this.web3.eth.sendSignedTransaction(signed.rawTransaction);
  }
}

